namespace optiling {

static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
static constexpr uint32_t ALIGN = 16;
static constexpr uint32_t MAX_TILE_H = 8;
static constexpr uint32_t MAX_TILE_W = 8;

static uint32_t AlignDown(uint32_t x, uint32_t a) {
    return (x / a) * a;
}

static ge::graphStatus TilingFunc(gert::TilingContext *context) {
    Conv2dMishMishCustomTilingData tiling;

    const gert::Shape *x_shape = context->GetInputShape(0);
    const gert::Shape *w_shape = context->GetInputShape(1);
    const gert::RuntimeAttrs *attrs = context->GetAttrs();

    tiling.n = x_shape->GetDim(0);
    tiling.cIn = x_shape->GetDim(1);
    tiling.hIn = x_shape->GetDim(2);
    tiling.wIn = x_shape->GetDim(3);
    tiling.k = w_shape->GetDim(0);
    tiling.r = w_shape->GetDim(2);
    tiling.s = w_shape->GetDim(3);
    uint32_t stride = attrs->GetAttrPointer<uint32_t>(0)[0];
    uint32_t padding = attrs->GetAttrPointer<uint32_t>(1)[0];
    uint32_t dilation = attrs->GetAttrPointer<uint32_t>(2)[0];
    tiling.stride = stride;
    tiling.padding = padding;
    tiling.dilation = dilation;

    tiling.hOut = (tiling.hIn + 2 * padding - dilation * (tiling.r - 1) - 1) / stride + 1;
    tiling.wOut = (tiling.wIn + 2 * padding - dilation * (tiling.s - 1) - 1) / stride + 1;

    // Choose tile sizes for output spatial dims
    uint32_t totalOutElems = tiling.n * tiling.k * tiling.hOut * tiling.wOut;
    uint32_t bytesPerElem = 4;
    uint32_t tileH = std::min(MAX_TILE_H, tiling.hOut);
    uint32_t tileW = std::min(MAX_TILE_W, tiling.wOut);
    // Adjust based on UB budget: need fraction for im2col + weight + output + mish temps
    // Rough: for each tile, need (tileH*tileW * cIn * r * s + k * cIn * r * s + tileH*tileW*k) * 4 bytes
    // plus double buffers. For simplicity, use fixed small tiles.
    if (tileH * tileW * tiling.cIn * tiling.r * tiling.s * 4 > UB_BUDGET_BYTES * 0.4) {
        tileH = std::max(1u, tileH / 2);
        tileW = std::max(1u, tileW / 2);
    }

    tiling.tileH = AlignDown(tileH, ALIGN);
    if (tiling.tileH < 1) tiling.tileH = 1;
    tiling.tileW = AlignDown(tileW, ALIGN);
    if (tiling.tileW < 1) tiling.tileW = 1;

    uint32_t numTiles = ((tiling.hOut + tiling.tileH - 1) / tiling.tileH) * ((tiling.wOut + tiling.tileW - 1) / tiling.tileW);
    tiling.blockDim = std::min(numTiles, 24u);
    if (tiling.blockDim < 8u) tiling.blockDim = 8u;

    context->SetBlockDim(tiling.blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

