#include <torch/library.h>
#include <torch/extension.h>
#include "pytorch_npu_helper.hpp"
#include <vector>

at::Tensor conv2d_mish_impl_npu(const at::Tensor& self, const at::Tensor& weight,
                                c10::optional<at::Tensor> bias,
                                int64_t stride, int64_t padding, int64_t dilation, int64_t groups) {
    auto result = at::empty({self.size(0), weight.size(0),
                             (self.size(2) + 2 * padding - dilation * (weight.size(2) - 1) - 1) / stride + 1,
                             (self.size(3) + 2 * padding - dilation * (weight.size(3) - 1) - 1) / stride + 1},
                            self.options());
    if (bias.has_value()) {
        EXEC_NPU_CMD(aclnnConv2dMishMishCustom, self, weight, bias.value(), result, stride, padding, dilation, groups);
    } else {
        EXEC_NPU_CMD(aclnnConv2dMishMishCustom, self, weight, at::Tensor(), result, stride, padding, dilation, groups);
    }
    return result;
}

TORCH_LIBRARY_IMPL(myops, PrivateUse1, m) {
    m.impl("conv2d_mish_mish_custom", &conv2d_mish_impl_npu);
}

